// src/app/page.tsx
"use client";

import { useState } from 'react';
import { calcularPedido, PRECO_PAO } from '../lib/priceCalc';

export default function Home() {
  const [qtd, setQtd] = useState(10);
  const taxaFixa = 3.00; // Taxa de entrega fixa para o MVP

  const { subtotal, taxa, total } = calcularPedido(qtd, taxaFixa);

  return (
    <main style={{ 
      minHeight: '100vh', 
      backgroundColor: '#f9f9f9', 
      fontFamily: 'sans-serif',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      padding: '20px'
    }}>
      
      {/* Cabeçalho */}
      <div style={{
        backgroundColor: '#b30000', // Vermelho da Padaria Real
        color: '#ffd700', // Amarelo
        width: '100%',
        maxWidth: '400px',
        padding: '20px',
        borderRadius: '12px',
        textAlign: 'center',
        boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
      }}>
        <h1 style={{ margin: 0, fontSize: '24px' }}>🥖 Padaria Real</h1>
        <p style={{ margin: '5px 0 0 0', fontSize: '14px', color: '#fff' }}>Delivery Rápido</p>
      </div>

      {/* Card do Pedido */}
      <div style={{
        backgroundColor: '#fff',
        width: '100%',
        maxWidth: '400px',
        marginTop: '20px',
        padding: '20px',
        borderRadius: '12px',
        boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
        boxSizing: 'border-box'
      }}>
        <h2 style={{ fontSize: '18px', color: '#333', marginBottom: '15px' }}>Faça seu pedido</h2>
        
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <span style={{ fontSize: '16px', color: '#666' }}>Pão Francês (Unidade)</span>
          <span style={{ fontWeight: 'bold', color: '#b30000' }}>R$ {PRECO_PAO.toFixed(2)}</span>
        </div>

        {/* Controle de Quantidade */}
        <div style={{ display: 'flex', flexDirection: 'column', marginBottom: '20px' }}>
          <label style={{ fontSize: '14px', color: '#666', marginBottom: '8px' }}>Quantidade de pães:</label>
          <div style={{ display: 'flex', gap: '10px' }}>
            <button 
              onClick={() => setQtd(qtd > 1 ? qtd - 1 : 1)}
              style={{ padding: '10px 20px', fontSize: '20px', border: 'none', borderRadius: '8px', backgroundColor: '#eee', cursor: 'pointer' }}
            >-</button>
            
            <input 
              type="number" 
              value={qtd} 
              onChange={(e) => setQtd(Number(e.target.value))} 
              style={{ flex: 1, textAlign: 'center', fontSize: '18px', border: '1px solid #ccc', borderRadius: '8px' }}
            />
            
            <button 
              onClick={() => setQtd(qtd + 1)}
              style={{ padding: '10px 20px', fontSize: '20px', border: 'none', borderRadius: '8px', backgroundColor: '#eee', cursor: 'pointer' }}
            >+</button>
          </div>
        </div>

        {/* Resumo Financeiro */}
        <div style={{ borderTop: '1px dashed #ccc', paddingTop: '15px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', color: '#666' }}>
            <span>Subtotal:</span>
            <span>R$ {subtotal}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px', color: '#666' }}>
            <span>Taxa de entrega:</span>
            <span>R$ {taxa}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '20px', fontWeight: 'bold', color: '#333' }}>
            <span>Total:</span>
            <span>R$ {total}</span>
          </div>
        </div>
      </div>
      
      {/* Botão de Ação */}
      <button style={{ 
        width: '100%', 
        maxWidth: '400px', 
        marginTop: '20px', 
        padding: '15px', 
        backgroundColor: '#25D366', // Verde do WhatsApp
        color: 'white', 
        border: 'none', 
        borderRadius: '8px', 
        fontSize: '18px', 
        fontWeight: 'bold',
        cursor: 'pointer',
        boxShadow: '0 4px 6px rgba(37, 211, 102, 0.3)'
      }}>
        Enviar Pedido por WhatsApp
      </button>

    </main>
  );
}